module RefModule(
    input  clk,
    input  reset,
    input  dir,
    output [3:0] count
);

reg [3:0] unused_count_reg;

always @(posedge clk) begin
    if (reset) begin
        unused_count_reg <= 4'b0000;
    end else if (dir) begin
        unused_count_reg <= unused_count_reg + 1;
    end else begin
        unused_count_reg <= unused_count_reg - 1;
    end
end

assign count = unused_count_reg;

endmodule
